_MOMENTS = len(_MOMENT_FNS)


class MomentBasedGaussianPolynomial:
    """Gaussian orthogonal polynomial defined by the moments of a distribution.

    # C++ parity: ql/math/integrals/momentbasedgaussianpolynomial.hpp.

    Subclasses implement :meth:`moment` (the ``i``-th raw moment). The base
    builds the three-term-recurrence coefficients ``alpha`` / ``beta`` lazily
    via the modified-moment determinant recursion ``z(k, i)``.

    This is the ``mp_real == Real`` (double-precision) specialization of the
    C++ class template; it is ported under ``experimental.math`` because its
    only concrete user in scope is the non-central chi-squared polynomial.
    """

    __slots__ = ("_b", "_c", "_z_tab")

    def __init__(self) -> None:
        self._z_tab: list[list[float]] = [[]]
        self._b: list[float] = []
        self._c: list[float] = []

    def moment(self, i: int) -> float:
        """The ``i``-th raw moment of the distribution. Override in subclasses."""
        raise NotImplementedError

    def mu_0(self) -> float:
        """Zeroth moment (the total mass); must equal one."""
        m0 = self.moment(0)
        qassert.require(close_enough(m0, 1.0), "zero moment must by one.")
        return self.moment(0)

    def alpha(self, u: int) -> float:
        """``alpha`` recurrence coefficient at index ``u``."""
        return self._alpha(u)

    def beta(self, u: int) -> float:
        """``beta`` recurrence coefficient at index ``u``."""
        return self._beta(u)

    # ---- internal modified-moment recursion ----

    def _z(self, k: int, i: int) -> float:
        if k == -1:
            return 0.0
        rows = len(self._z_tab)
        cols = len(self._z_tab[0])
        if cols <= i:
            for row in self._z_tab:
                row.extend([nan] * (i + 1 - len(row)))
        if rows <= k:
            width = len(self._z_tab[0])
            for _ in range(k + 1 - rows):
                self._z_tab.append([nan] * width)
        if isnan(self._z_tab[k][i]):
            if k == 0:
                self._z_tab[k][i] = self.moment(i)
            else:
                self._z_tab[k][i] = (
                    self._z(k - 1, i + 1)
                    - self._alpha(k - 1) * self._z(k - 1, i)
                    - self._beta(k - 1) * self._z(k - 2, i)
                )
        return self._z_tab[k][i]

    def _alpha(self, u: int) -> float:
        if len(self._b) <= u:
            self._b.extend([nan] * (u + 1 - len(self._b)))
        if isnan(self._b[u]):
            if u == 0:
                self._b[u] = self.moment(1)
            else:
                self._b[u] = (
                    -self._z(u - 1, u) / self._z(u - 1, u - 1)
                    + self._z(u, u + 1) / self._z(u, u)
                )
        return self._b[u]

    def _beta(self, u: int) -> float:
        if u == 0:
            return 1.0
        if len(self._c) <= u:
            self._c.extend([nan] * (u + 1 - len(self._c)))
        if isnan(self._c[u]):
            self._c[u] = self._z(u, u) / self._z(u - 1, u - 1)
        return self._c[u]


class GaussianNonCentralChiSquaredPolynomial(MomentBasedGaussianPolynomial):
    """Orthogonal polynomial of the non-central chi-squared distribution.

    :param nu: degrees of freedom.
    :param lam: non-centrality parameter (C++ ``lambda``).
    """

    __slots__ = ("_lambda", "_nu")

    def __init__(self, nu: float, lam: float) -> None:
        super().__init__()
        self._nu = nu
        self._lambda = lam

    def moment(self, i: int) -> float:
        qassert.require(
            i < _MOMENTS,
            f"order ({i}) must be < {_MOMENTS}",
        )
        return _MOMENT_FNS[i](self._nu, self._lambda)

    def w(self, x: float) -> float:
        """Weight function: the non-central chi-squared pdf at ``x``."""
        return float(ncx2.pdf(x, self._nu, self._lambda))  # pyright: ignore[reportUnknownArgumentType, reportUnknownMemberType]


# Alias matching the C++ class name spelling (GaussNonCentralChiSquaredPolynomial).
GaussNonCentralChiSquaredPolynomial = GaussianNonCentralChiSquaredPolynomial
